  bool _isKeyboardVisible = false;

  @override
  void initState() {
    super.initState();
    _model = createModel(context, () => CartSubscriptionScreenModel());

    logFirebaseEvent('screen_view',
        parameters: {'screen_name': 'cartSubscriptionScreen'});
    // On page load action.
    SchedulerBinding.instance.addPostFrameCallback((_) async {
      logFirebaseEvent('CART_SUBSCRIPTION_SCREEN_cartSubscriptio');
      logFirebaseEvent('cartSubscriptionScreen_update_app_state');
      FFAppState().searchScreenNaviagtion = 'subscription';
      FFAppState().deliveryPartnerInstructionAvoid = '';
      FFAppState().deliveryPartnerInstructionBell = '';
      FFAppState().deliveryPartnerInstructionDoor = '';
