      logFirebaseEvent('cartSubscriptionScreen_update_page_state');
      _model.isPaymentDone = true;
      safeSetState(() {});
      logFirebaseEvent('cartSubscriptionScreen_backend_call');
      _model.apiResultaWeeks = await QuickartGroup.totaldeliveriesCall.call();

      if ((_model.apiResultaWeeks?.succeeded ?? true)) {
        logFirebaseEvent('cartSubscriptionScreen_update_app_state');
        FFAppState().varientID = 0;
        FFAppState().isSubCartVisible = false;
      }
      if (FFAppState().screenName == 'addCard') {
        logFirebaseEvent('cartSubscriptionScreen_backend_call');
        _model.apiResultBankDetail =
            await QuickartGroup.userbankdetailsCall.call(
          userid: FFAppState().userID,
        );

        if ((_model.apiResultBankDetail?.succeeded ?? true)) {
          logFirebaseEvent('cartSubscriptionScreen_update_app_state');
          FFAppState().selectedCardID = getJsonField(
            QuickartGroup.userbankdetailsCall
                .data(
                  (_model.apiResultBankDetail?.jsonBody ?? ''),
                )!
                .lastOrNull,
            r'''$.si_sub_ref_no''',
          ).toString();
          FFAppState().isCardChange = true;
          FFAppState().selectedCardNumber = getJsonField(
            QuickartGroup.userbankdetailsCall
                .data(
                  (_model.apiResultBankDetail?.jsonBody ?? ''),
                )!
                .lastOrNull,
            r'''$.card_no''',
          ).toString();
          FFAppState().paymentMethod = 'Card';
          FFAppState().selectedSINumber = getJsonField(
            QuickartGroup.userbankdetailsCall
                .data(
                  (_model.apiResultBankDetail?.jsonBody ?? ''),
                )!
                .lastOrNull,
            r'''$.si_sub_ref_no''',
          ).toString();
          FFAppState().cardnodemo = getJsonField(
            QuickartGroup.userbankdetailsCall
                .data(
                  (_model.apiResultBankDetail?.jsonBody ?? ''),
                )!
                .lastOrNull,
            r'''$.si_sub_ref_no''',
          ).toString();
          FFAppState().varientID = 0;
          FFAppState().isSubCartVisible = false;
          safeSetState(() {});
        }
      }
    });

    if (!isWeb) {
      _keyboardVisibilitySubscription =
          KeyboardVisibilityController().onChange.listen((bool visible) {
        safeSetState(() {
          _isKeyboardVisible = visible;
        });
      });
    }

    _model.tabBarController = TabController(
      vsync: this,
      length: 2,
      initialIndex: 1,
    )..addListener(() => safeSetState(() {}));

    _model.textController ??= TextEditingController();
    _model.textFieldFocusNode ??= FocusNode();

    WidgetsBinding.instance.addPostFrameCallback((_) => safeSetState(() {}));
  }

  @override
  void dispose() {
    _model.dispose();

    if (!isWeb) {
      _keyboardVisibilitySubscription.cancel();
    }
    super.dispose();
  }

